sys_ui_script.script:
function ShowNowAssistPanel(strConversationSysId)
{
	console.log('ShowNowAssistPanel ' + strConversationSysId);



	//return;

	//NowAssistPanelMessageAutoExpand();

  (function () {
    function injectAndRunTop(fnText, callText) {
      var topDoc = window.top.document;

      var VERSION = "nowAssistPanelAutomation_v7_2026-03-02";
      if (window.top.__nowAssistPanelAutomationVersion !== VERSION) {
        var s = topDoc.createElement("script");
        s.type = "text/javascript";
        s.text =
          "window.__nowAssistPanelAutomationVersion=" +
          JSON.stringify(VERSION) +
          ";\n" +
          fnText;
        topDoc.head.appendChild(s);
      }

      var s2 = topDoc.createElement("script");
      s2.type = "text/javascript";
      s2.text = callText;
      topDoc.head.appendChild(s2);
    }

    var sysId =
      typeof strConversationSysId === "string" && /^[0-9a-f]{32}$/i.test(strConversationSysId)
        ? strConversationSysId
        : "";

    var TOP_RUNNER = String.raw`
(function(){
  var DEBUG = false; // flip to true if you want console output

  function log(){
    if(!DEBUG) return;
    try{ console.log.apply(console, ["[NowAssistPanelV7]"].concat([].slice.call(arguments))); }catch(e){}
  }

  function norm(s){
    return ((s||"")+"").toLowerCase().replace(/\\s+/g," ").trim();
  }
  function isSysId(s){ return /^[0-9a-f]{32}$/i.test((s||"")+""); }

  function isVisible(el){
    if(!el) return false;
    try{
      var r=el.getBoundingClientRect();
      var s=getComputedStyle(el);
      return r.width>0 && r.height>0 && s.display!=="none" && s.visibility!=="hidden" && s.opacity!=="0";
    }catch(e){ return false; }
  }

  function buttonLike(el){
    if(!el || el.nodeType!==1) return false;
    var tag=(el.tagName||"").toLowerCase();
    var role=(el.getAttribute && el.getAttribute("role")) || "";
    return tag==="button" || role==="button" || (tag==="a" && role==="button") ||
      ((tag==="div"||tag==="span") && el.getAttribute && el.getAttribute("tabindex")!==null);
  }

  function closestClickable(el){
    var cur=el;
    for(var i=0; cur && i<10; i++){
      if(buttonLike(cur)) return cur;
      var role=norm(cur.getAttribute && (cur.getAttribute("role")||""));
      if(role==="option"||role==="listitem"||role==="menuitem"||role==="menuitemradio") return cur;
      cur=cur.parentElement;
    }
    return el;
  }

  function realClick(el){
    if(!el) return false;
    try{
      ["pointerdown","mousedown","pointerup","mouseup","click"].forEach(function(t){
        el.dispatchEvent(new MouseEvent(t,{bubbles:true,cancelable:true,view:window}));
      });
      return true;
    }catch(e){
      try{ el.click(); return true; }catch(e2){ return false; }
    }
  }

  function deepWalkAll(startNode, visitor, maxNodes){
    var q=[startNode], scanned=0;
    var seen=new WeakSet();
    while(q.length && scanned<maxNodes){
      var n=q.shift();
      if(!n) continue;
      try{ if(seen.has(n)) continue; seen.add(n); }catch(e){}
      scanned++;

      if(n.nodeType===1){
        try{ visitor(n); }catch(e){}
      }

      if(n.nodeType===1 && (n.tagName||"").toLowerCase()==="iframe"){
        try{
          var idoc=n.contentDocument;
          if(idoc && idoc.body) q.push(idoc.body);
        }catch(e){}
      }

      var kids=n.children||n.childNodes;
      if(kids && kids.length){
        for(var i=0;i<kids.length;i++) q.push(kids[i]);
      }
      if(n.shadowRoot) q.push(n.shadowRoot);
    }
  }

  // ===== Strong "panel open" signal =====
  function findUnpinButton(){
    var hit=null;
    deepWalkAll(window.document.body,function(el){
      if(hit) return;
      if(!isVisible(el) || !buttonLike(el)) return;
      if(norm(el.getAttribute && el.getAttribute("aria-label"))==="unpin now assist") hit=el;
    },120000);
    return hit;
  }

  function isPanelOpen(){ return !!findUnpinButton(); }

  function findPanelRootFromUnpin(unpinBtn){
    if(!unpinBtn) return null;
    var cur=unpinBtn, best=null;
    for(var i=0; cur && i<25; i++){
      try{
        var r=cur.getBoundingClientRect();
        if(isVisible(cur) && r.width>=250 && r.height>=200) best=cur;
      }catch(e){}
      cur=cur.parentElement;
    }
    return best || unpinBtn;
  }

  function expandRect(r, px){
    return { left:r.left-px, right:r.right+px, top:r.top-px, bottom:r.bottom+px };
  }
  function rectIntersects(a,b){
    return !(a.right<b.left || a.left>b.right || a.bottom<b.top || a.top>b.bottom);
  }

  // ===== Launcher (open panel) =====
  function findLauncher(){
    var hit=null;
    deepWalkAll(window.document.body,function(el){
      if(hit) return;
      if(!isVisible(el) || !buttonLike(el)) return;
      var cls=norm((typeof el.className==="string") ? el.className : "");
      var lab=norm(el.getAttribute && el.getAttribute("aria-label"));
      if(cls.indexOf("now-assist-button")!==-1 || lab==="now assist") hit=el;
    },120000);
    return hit;
  }

  function launcherState(btn){
    if(!btn) return {known:false, open:false};
    var exp=btn.getAttribute && btn.getAttribute("aria-expanded");
    if(exp==="true") return {known:true, open:true};
    if(exp==="false") return {known:true, open:false};
    var prs=btn.getAttribute && btn.getAttribute("aria-pressed");
    if(prs==="true") return {known:true, open:true};
    if(prs==="false") return {known:true, open:false};
    return {known:false, open:false};
  }

  // ===== SysId-only switching strategy A: iframe URL replacement =====
  function trySwitchViaIframe(panelRect, targetSysId){
    var region=expandRect(panelRect, 80);
    var frames=[];
    deepWalkAll(window.document.body,function(el){
      if((el.tagName||"").toLowerCase()!=="iframe") return;
      if(!isVisible(el)) return;
      try{
        var r=el.getBoundingClientRect();
        if(!rectIntersects(r, region)) return;
      }catch(e){ return; }
      frames.push(el);
    },120000);

    for(var i=0;i<frames.length;i++){
      var f=frames[i];
      try{
        if(!f.contentWindow || !f.contentWindow.location) continue;
        var href=""+f.contentWindow.location.href;
        // Try to find a conversation-like id segment in URL/hash
        var m =
          href.match(/(conversation|chat)[^0-9a-f]{0,10}([0-9a-f]{32})/i) ||
          href.match(/([0-9a-f]{32})/i);
        if(!m) continue;

        var currentId = (m[2] || m[1] || "").toLowerCase();
        if(!currentId || currentId === targetSysId.toLowerCase()) {
          // already there or unknown
          continue;
        }

        var newHref = href.replace(new RegExp(currentId, "ig"), targetSysId);
        log("Iframe switch:", {href: href, newHref: newHref});
        f.contentWindow.location.href = newHref;
        return true;
      }catch(e){
        // ignore (cross-origin or blocked)
      }
    }
    return false;
  }

  // ===== SysId-only switching strategy B: list click by sys_id in DOM =====
  function elementHasSysId(el, targetLower){
    if(!el || el.nodeType!==1) return false;

    var attrs=["data-conversation-id","data-conversationid","data-sys-id","data-sysid","data-id","id","href","value","name"];
    for(var i=0;i<attrs.length;i++){
      var v=el.getAttribute && el.getAttribute(attrs[i]);
      if(v && ((""+v).toLowerCase().indexOf(targetLower)!==-1)) return true;
    }

    try{
      if(el.dataset){
        for(var k in el.dataset){
          if(!Object.prototype.hasOwnProperty.call(el.dataset,k)) continue;
          var dv=(el.dataset[k]||"")+"";
          if(dv.toLowerCase().indexOf(targetLower)!==-1) return true;
        }
      }
    }catch(e){}

    return false;
  }

  function findConversationElementNearPanel(panelRect, targetSysId){
    var targetLower = (targetSysId||"").toLowerCase();
    var region = expandRect(panelRect, 80);
    var hit = null;

    deepWalkAll(window.document.body,function(el){
      if(hit) return;
      if(!isVisible(el)) return;

      try{
        var r=el.getBoundingClientRect();
        if(!rectIntersects(r, region)) return;
      }catch(e){ return; }

      if(elementHasSysId(el, targetLower)) hit = closestClickable(el);
    },250000);

    return hit;
  }

  function findScrollableListNearPanel(panelRect){
    var region = expandRect(panelRect, 80);
    var best = null;

    deepWalkAll(window.document.body,function(el){
      if(best) return;
      if(!isVisible(el)) return;

      try{
        var r=el.getBoundingClientRect();
        if(!rectIntersects(r, region)) return;

        var s=getComputedStyle(el);
        var oy=norm(s.overflowY);
        if((oy==="auto"||oy==="scroll") && el.scrollHeight > el.clientHeight + 50){
          best = el;
        }
      }catch(e){}
    },250000);

    return best;
  }

  // Show list: click the leftmost header control in the “Chats” row (best effort).
  // Docs: conversation list opened via “All chats” icon. :contentReference[oaicite:2]{index=2}
  function ensureListVisible(panelRoot){
    // Heuristic: if we see “Active” and “Closed” labels inside panel bounds, assume list is visible.
    var box;
    try{ box = panelRoot.getBoundingClientRect(); }catch(e){ return false; }

    var hasActive=false, hasClosed=false;
    deepWalkAll(panelRoot,function(el){
      if(!isVisible(el)) return;
      var t = norm(el.textContent||"");
      if(t==="active") hasActive=true;
      if(t==="closed") hasClosed=true;
    },80000);

    if(hasActive || hasClosed) return true;

    // Find “Chats” label and click the nearest button to its left.
    var chatsEl=null;
    deepWalkAll(panelRoot,function(el){
      if(chatsEl) return;
      if(!isVisible(el)) return;
      if(norm(el.textContent||"")==="chats") chatsEl=el;
    },80000);

    if(!chatsEl) return false;

    var chatsRect;
    try{ chatsRect = chatsEl.getBoundingClientRect(); }catch(e){ return false; }

    var candidates=[];
    deepWalkAll(panelRoot,function(el){
      if(!buttonLike(el) || !isVisible(el)) return;
      try{
        var r=el.getBoundingClientRect();
        // same row-ish, left of Chats, close distance
        var sameBand = Math.abs((r.top+r.bottom)/2 - (chatsRect.top+chatsRect.bottom)/2) < 25;
        var leftOf = r.right <= chatsRect.left + 10;
        var close = (chatsRect.left - r.right) < 120;
        if(sameBand && leftOf && close) candidates.push(el);
      }catch(e){}
    },120000);

    candidates.sort(function(a,b){
      try{ return b.getBoundingClientRect().right - a.getBoundingClientRect().right; }catch(e){ return 0; }
    });

    if(candidates[0]){
      realClick(candidates[0]);
      return false; // allow UI to render list then next tick sees it
    }

    return false;
  }

  function trySwitchViaList(panelRoot, targetSysId){
    var panelRect;
    try{ panelRect = panelRoot.getBoundingClientRect(); }catch(e){ return false; }

    // Ensure list is visible (All chats icon / hamburger)
    ensureListVisible(panelRoot);

    // Try direct sys_id match near the panel
    var el = findConversationElementNearPanel(panelRect, targetSysId);
    if(el){
      realClick(el);
      return true;
    }

    // Virtualized list: scroll and re-scan
    var sc = findScrollableListNearPanel(panelRect);
    if(sc){
      try{
        var before = sc.scrollTop;
        sc.scrollTop = Math.min(sc.scrollTop + sc.clientHeight * 0.8, sc.scrollHeight);
        if(sc.scrollTop !== before) log("Scrolled list...");
      }catch(e){}
    }

    return false;
  }

  // ===== Runner (self-terminating; respects user close) =====
  function stop(reason){
    try{
      if(window.__nowAssistAutomationTimerV7){
        clearInterval(window.__nowAssistAutomationTimerV7);
        window.__nowAssistAutomationTimerV7=null;
      }
      window.__nowAssistAutomationStateV7=null;
    }catch(e){}
    log("STOP:", reason);
  }
  window.__nowAssistAutomationStopV7 = function(){ stop("manual_stop"); };

  window.nowAssistOpenAndSelectConversationV7 = function(conversationSysId){
    try{ if(window.__nowAssistAutomationTimerV7) clearInterval(window.__nowAssistAutomationTimerV7); }catch(e){}

    var target = isSysId(conversationSysId) ? conversationSysId : "";
    var startedAt = Date.now();

    var state = {
      target: target,
      startedAt: startedAt,
      openedAt: null,
      seenOpen: false,
      lastLauncherClick: 0,
      iframeAttempted: false
    };
    window.__nowAssistAutomationStateV7 = state;

    var MAX_OPEN_MS   = 4000;
    var MAX_SWITCH_MS = 9000;

    function tick(){
      var now = Date.now();
      var open = isPanelOpen();

      // If user closes after we saw it open, stop and never re-open
      if(state.seenOpen && !open){
        stop("user_closed_after_open");
        return;
      }

      // Open phase
      if(!open){
        if(now - state.startedAt > MAX_OPEN_MS){
          stop("open_timeout");
          return;
        }

        var launcher = findLauncher();
        if(!launcher) return;

        var st = launcherState(launcher);
        if(st.known && st.open) return;

        if(now - state.lastLauncherClick > 1200){
          state.lastLauncherClick = now;
          realClick(launcher);
        }
        return;
      }

      // Opened
      if(!state.seenOpen){
        state.seenOpen = true;
        state.openedAt = now;
      }

      if(!state.target){
        stop("opened_no_target");
        return;
      }

      if(now - state.openedAt > MAX_SWITCH_MS){
        stop("switch_timeout");
        return;
      }

      var unpin = findUnpinButton();
      if(!unpin) return;

      var panelRoot = findPanelRootFromUnpin(unpin);
      if(!panelRoot) return;

      var panelRect;
      try{ panelRect = panelRoot.getBoundingClientRect(); }catch(e){ return; }

      // Strategy A: iframe route replace (once)
      if(!state.iframeAttempted){
        state.iframeAttempted = true;
        if(trySwitchViaIframe(panelRect, state.target)){
          stop("switched_via_iframe");
          return;
        }
      }

      // Strategy B: DOM list sys_id click (repeat until timeout)
      if(trySwitchViaList(panelRoot, state.target)){
        stop("switched_via_list_click");
        return;
      }
    }

    window.__nowAssistAutomationTimerV7 = setInterval(tick, 250);
		//window.aiex.launch({"conversationId": strConversationSysId }); 

  };
})();`;

    injectAndRunTop(
      TOP_RUNNER,
      "window.nowAssistOpenAndSelectConversationV7 && window.nowAssistOpenAndSelectConversationV7(" +
        JSON.stringify(sysId) +
        ");"
    );
  })();
}
